/** Shape dashboardService.js needs: no assignedUserIds on actualsItems (matches the real asymmetry). */
export function generateDashboardData() {
  return {
    planningItems: DATA.planningItems,
    actualsItems: DATA.actualsItems.map(({ assignedUserIds, ...rest }) => rest),
  };
}

/** Shape workloadService.js needs: includes users + assignedUserIds. */
export function generateWorkloadData() {
  return { planningItems: DATA.planningItems, actualsItems: DATA.actualsItems, users: DATA.users };
}
